class SecureTopicValidator:
    def __init__(self, allowed_topics: Optional[Set[str]] = None, 
                 allowed_prefixes: Optional[Set[str]] = None):
        self.allowed_topics = allowed_topics or set()
        self.allowed_prefixes = allowed_prefixes or set()
        self.topic_pattern = re.compile(r'^[a-zA-Z0-9._-]+$')
        self.max_topic_length = 249
        
    def validate_topic(self, topic_name: str) -> tuple[bool, str]:
        if not topic_name:
            return False, "Topic name cannot be empty"
        
        if len(topic_name) > self.max_topic_length:
            return False, f"Topic name exceeds maximum length of {self.max_topic_length}"
        
        if not self.topic_pattern.match(topic_name):
            return False, "Topic name contains invalid characters. Only alphanumeric, dots, underscores, and hyphens allowed"
        
        if topic_name.startswith('.') or topic_name.startswith('_'):
            return False, "Topic name cannot start with '.' or '_'"
        
        if '..' in topic_name:
            return False, "Topic name cannot contain consecutive dots"
        
        if self.allowed_topics and topic_name not in self.allowed_topics:
            return False, f"Topic '{topic_name}' is not in the allowed topics list"
        
        if self.allowed_prefixes:
            if not any(topic_name.startswith(prefix) for prefix in self.allowed_prefixes):
                return False, f"Topic must start with one of the allowed prefixes: {', '.join(self.allowed_prefixes)}"
        
        return True, "Valid topic"


class SecureKafkaProducer:
    def __init__(self, bootstrap_servers: list, 
                 allowed_topics: Optional[Set[str]] = None,
                 allowed_prefixes: Optional[Set[str]] = None,
                 enable_ssl: bool = True,
                 sasl_mechanism: str = 'PLAIN',
                 sasl_username: Optional[str] = None,
                 sasl_password: Optional[str] = None):
        
        self.validator = SecureTopicValidator(allowed_topics, allowed_prefixes)
        
        producer_config = {
            'bootstrap_servers': bootstrap_servers,
            'value_serializer': lambda v: json.dumps(v).encode('utf-8'),
            'key_serializer': lambda k: k.encode('utf-8') if k else None,
            'acks': 'all',
            'retries': 3,
            'max_in_flight_requests_per_connection': 1,
            'compression_type': 'gzip'
        }
        
        if enable_ssl:
            producer_config.update({
                'security_protocol': 'SASL_SSL',
                'sasl_mechanism': sasl_mechanism,
                'sasl_plain_username': sasl_username,
                'sasl_plain_password': sasl_password,
                'ssl_check_hostname': True
            })
        
        self.producer = KafkaProducer(**producer_config)
        logger.info("Secure Kafka producer initialized")
    
    def publish_message(self, topic_name: str, message: dict, 
                       key: Optional[str] = None, 
                       user_id: Optional[str] = None) -> tuple[bool, str]:
        
        is_valid, validation_message = self.validator.validate_topic(topic_name)
        if not is_valid:
            logger.warning(f"Topic validation failed for '{topic_name}': {validation_message}")
            return False, validation_message
        
        try:
            sanitized_message = self._sanitize_message(message)
            
            if user_id:
                sanitized_message['_metadata'] = {
                    'user_id': user_id,
                    'message_hash': self._generate_message_hash(sanitized_message)
                }
            
            future = self.producer.send(
                topic=topic_name,
                value=sanitized_message,
                key=key
            )
            
            record_metadata = future.get(timeout=10)
            
            logger.info(f"Message published to topic '{topic_name}' "
                       f"partition {record_metadata.partition} "
                       f"offset {record_metadata.offset}")
            
            return True, f"Message published successfully to {topic_name}"
            
        except KafkaError as e:
            logger.error(f"Kafka error publishing to '{topic_name}': {str(e)}")
            return False, f"Failed to publish message: {str(e)}"
        except Exception as e:
            logger.error(f"Unexpected error publishing to '{topic_name}': {str(e)}")
            return False, f"Unexpected error: {str(e)}"
    
    def _sanitize_message(self, message: dict) -> dict:
        if not isinstance(message, dict):
            raise ValueError("Message must be a dictionary")
        
        sanitized = {}
        for key, value in message.items():
            if isinstance(key, str) and len(key) <= 256:
                if isinstance(value, (str, int, float, bool, type(None))):
                    sanitized[key] = value
                elif isinstance(value, (list, dict)):
                    sanitized[key] = value
        
        return sanitized
    
    def _generate_message_hash(self, message: dict) -> str:
        message_str = json.dumps(message, sort_keys=True)
        return hashlib.sha256(message_str.encode()).hexdigest()
    
    def close(self):
        self.producer.flush()
        self.producer.close()
        logger.info("Kafka producer closed")


