@app.route('/publish', methods=['POST'])
def publish_message():
    try:
        topic_name = request.args.get('topic') or request.json.get('topic')
        message = request.json.get('message')
        key = request.json.get('key')
        user_id = request.headers.get('X-User-ID')
        
        if not topic_name:
            return jsonify({'error': 'Topic name is required'}), 400
        
        if not message:
            return jsonify({'error': 'Message is required'}), 400
        
        success, result_message = kafka_producer.publish_message(
            topic_name=topic_name,
            message=message,
            key=key,
            user_id=user_id
        )
        
        if success:
            return jsonify({'status': 'success', 'message': result_message}), 200
        else:
            return jsonify({'status': 'error', 'message': result_message}), 400
            
    except Exception as e:
        logger.error(f"Error in publish endpoint: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500


